```

answer_code:
using System;
using System.Linq;

class Program {
    static void Main() {
        int n = int.Parse(Console.ReadLine());
        int[] arr = Console.ReadLine().Split().Select(int.Parse).ToArray();
        Array.Reverse(arr);
        Console.WriteLine(string.Join(" ", arr));
    }
}
